import os

def extract_tar_to_path(tar_path, dest_path) -> bool:
    try:
        abs_dest = os.path.abspath(dest_path)
        with tarfile.open(tar_path, 'r:*') as tar:
            for member in tar.getmembers():
                member_path = os.path.abspath(os.path.join(abs_dest, member.name))
                if not (member_path == abs_dest or member_path.startswith(abs_dest + os.sep)):
                    return False
                if member.issym() or member.islnk():
                    link_path = os.path.abspath(os.path.join(os.path.dirname(member_path), member.linkname))
                    if not (link_path == abs_dest or link_path.startswith(abs_dest + os.sep)):
                        return False
            tar.extractall(dest_path)
        return True
    except Exception:
        return False

