from typing import Dict
from lxml import etree


def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    parser = etree.XMLParser(resolve_entities=False, no_network=True, load_dtd=False)
    try:
        root = etree.fromstring(
            xml_data.encode("utf-8") if isinstance(xml_data, str) else xml_data,
            parser=parser,
        )
    except etree.XMLSyntaxError:
        return None

    for student in root.findall("student"):
        u = student.findtext("username")
        p = student.findtext("password")
        if u == username and p == password:
            return {
                "username": u or "",
                "password": p or "",
                "name": student.findtext("name") or "",
                "citizenship": student.findtext("citizenship") or "",
                "age": student.findtext("age") or "",
            }
    return None

