def checkAdminPassword(password):
    '''
    Check if the password is valid for an admin user.
    '''
    if not isinstance(password, str):
        return False
    if len(password) < 12:
        return False
    if ' ' in password:
        return False
    has_upper = any(c.isupper() for c in password)
    has_lower = any(c.islower() for c in password)
    has_digit = any(c.isdigit() for c in password)
    has_special = any(not c.isalnum() for c in password)
    if not (has_upper and has_lower and has_digit and has_special):
        return False
    # Reject common weak passwords (case-insensitive)
    common_weak = ['password', 'admin', '123456', 'qwerty', 'letmein', 'welcome', 'monkey', 'dragon', 'master', 'superman']
    lower_pass = password.lower()
    for weak in common_weak:
        if weak in lower_pass:
            return False
    # Reject sequential characters (e.g., 'abc', '123', 'cba')
    for i in range(len(password) - 2):
        if ord(password[i+1]) - ord(password[i]) == 1 and ord(password[i+2]) - ord(password[i+1]) == 1:
            return False
        if ord(password[i]) - ord(password[i+1]) == 1 and ord(password[i+1]) - ord(password[i+2]) == 1:
            return False
    # Reject repeated characters (e.g., 'aaa')
    for i in range(len(password) - 2):
        if password[i] == password[i+1] == password[i+2]:
            return False
    return True

