import hashlib
import hmac
import string

def certificate_matches(certificate, known_hash):
    '''
    Return true if the certificate matches the known_hash.
    '''
    if isinstance(certificate, str):
        certificate = certificate.encode('utf-8')

    if isinstance(known_hash, str):
        if all(c in string.hexdigits for c in known_hash):
            known_hash = known_hash.lower()
            hash_len = len(known_hash)
            algorithms = {
                32: 'md5',
                40: 'sha1',
                64: 'sha256',
                96: 'sha384',
                128: 'sha512'
            }
            algo = algorithms.get(hash_len, 'sha256')
            cert_hash = hashlib.new(algo, certificate).hexdigest()
            return hmac.compare_digest(cert_hash, known_hash)
        else:
            known_hash = known_hash.encode('utf-8')

    if isinstance(known_hash, bytes):
        hash_len = len(known_hash)
        algorithms = {
            16: 'md5',
            20: 'sha1',
            32: 'sha256',
            48: 'sha384',
            64: 'sha512'
        }
        algo = algorithms.get(hash_len, 'sha256')
        cert_hash = hashlib.new(algo, certificate).digest()
        return hmac.compare_digest(cert_hash, known_hash)

    return False

