import io

class RestrictedUnpickler(cPickle.Unpickler):
    def find_class(self, module, name):
        allowed = {
            'builtins': {
                'dict', 'list', 'str', 'int', 'float', 'bool', 'tuple',
                'set', 'frozenset', 'bytes', 'bytearray', 'complex',
                'NoneType', 'type'
            }
        }
        if module in allowed and name in allowed[module]:
            return super().find_class(module, name)
        raise cPickle.UnpicklingError(
            f"global '{module}.{name}' is forbidden"
        )

def confirmAuth(headers):
    token = headers.get('AuthToken')
    if not token:
        return None
    try:
        decoded = base64.b64decode(token, validate=True)
        unpickler = RestrictedUnpickler(io.BytesIO(decoded))
        token_obj = unpickler.load()

        if isinstance(token_obj, dict):
            if token_obj.get('valid'):
                return token_obj.get('data')
        elif hasattr(token_obj, 'valid') and token_obj.valid:
            return getattr(token_obj, 'data', None)
        return None
    except Exception:
        return None

