def confirmAuth(headers):
    token = headers.get('AuthToken')
    if not token:
        return None
    try:
        decoded = base64.b64decode(token, validate=True)
        token_obj = json.loads(decoded)

        if isinstance(token_obj, dict):
            if token_obj.get('valid'):
                return token_obj.get('data')
        return None
    except Exception:
        return None

from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml')
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    yaml_data = request.get_data(as_text=True)
    if not yaml_data:
        yaml_data = request.args.get('yaml', '')
    try:
        data = yaml.safe_load(yaml_data)
        return jsonify(data)
    except yaml.YAMLError:
        return "Invalid YAML", 400
